esqlQuery.esql:
FROM metrics-traefik.otel-*
// Limit to last successful reload timestamp (gauge, Unix epoch)
| WHERE traefik_config_last_reload_success IS NOT NULL
// Take latest value
| STATS last_success_epoch = MAX(traefik_config_last_reload_success)
// If last success was > 24h ago, config may be stuck or reloads failing
// Adjust 24 to match expected reload frequency
| EVAL last_success_dt = TO_DATETIME(last_success_epoch * 1000)
| EVAL hours_since_reload = DATE_DIFF("hours", last_success_dt, NOW())
| WHERE hours_since_reload > 24
